package main
import "fmt"
func main() {
	m := map[int]int{7: 11, 2: 50, 9: 6, 0: 324}
	keys := []int{0, 2, 7, 9}
	acc := 0
	for _, k := range keys {
		v := m[k]
		acc = ((acc << 5) - acc) ^ (v + k)
	}
	fmt.Println(acc)
}

